<?php
 namespace League\CommonMark\Block\Parser; use League\CommonMark\Block\Element\ListBlock; use League\CommonMark\Block\Element\ListData; use League\CommonMark\Block\Element\ListItem; use League\CommonMark\Block\Element\Paragraph; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; use League\CommonMark\Util\RegexHelper; final class ListParser implements BlockParserInterface, ConfigurationAwareInterface { private $config; private $listMarkerRegex; public function setConfiguration(ConfigurationInterface $configuration) { $this->config = $configuration; } public function parse(ContextInterface $context, Cursor $cursor): bool { if ($cursor->isIndented() && !($context->getContainer() instanceof ListBlock)) { return false; } $indent = $cursor->getIndent(); if ($indent >= 4) { return false; } $tmpCursor = clone $cursor; $tmpCursor->advanceToNextNonSpaceOrTab(); $rest = $tmpCursor->getRemainder(); if (\preg_match($this->listMarkerRegex ?? $this->generateListMarkerRegex(), $rest) === 1) { $data = new ListData(); $data->markerOffset = $indent; $data->type = ListBlock::TYPE_BULLET; $data->delimiter = null; $data->bulletChar = $rest[0]; $markerLength = 1; } elseif (($matches = RegexHelper::matchFirst('/^(\d{1,9})([.)])/', $rest)) && (!($context->getContainer() instanceof Paragraph) || $matches[1] === '1')) { $data = new ListData(); $data->markerOffset = $indent; $data->type = ListBlock::TYPE_ORDERED; $data->start = (int) $matches[1]; $data->delimiter = $matches[2]; $data->bulletChar = null; $markerLength = \strlen($matches[0]); } else { return false; } $nextChar = $tmpCursor->peek($markerLength); if (!($nextChar === null || $nextChar === "\t" || $nextChar === ' ')) { return false; } $container = $context->getContainer(); if ($container instanceof Paragraph && !RegexHelper::matchAt(RegexHelper::REGEX_NON_SPACE, $rest, $markerLength)) { return false; } $cursor->advanceToNextNonSpaceOrTab(); $cursor->advanceBy($markerLength, true); $data->padding = $this->calculateListMarkerPadding($cursor, $markerLength); if (!($container instanceof ListBlock) || !$data->equals($container->getListData())) { $context->addBlock(new ListBlock($data)); } $context->addBlock(new ListItem($data)); return true; } private function calculateListMarkerPadding(Cursor $cursor, int $markerLength): int { $start = $cursor->saveState(); $spacesStartCol = $cursor->getColumn(); while ($cursor->getColumn() - $spacesStartCol < 5) { if (!$cursor->advanceBySpaceOrTab()) { break; } } $blankItem = $cursor->peek() === null; $spacesAfterMarker = $cursor->getColumn() - $spacesStartCol; if ($spacesAfterMarker >= 5 || $spacesAfterMarker < 1 || $blankItem) { $cursor->restoreState($start); $cursor->advanceBySpaceOrTab(); return $markerLength + 1; } return $markerLength + $spacesAfterMarker; } private function generateListMarkerRegex(): string { if ($this->config === null) { return $this->listMarkerRegex = '/^[*+-]/'; } $deprecatedMarkers = $this->config->get('unordered_list_markers', ConfigurationInterface::MISSING); if ($deprecatedMarkers !== ConfigurationInterface::MISSING) { @\trigger_error('The "unordered_list_markers" configuration option is deprecated in league/commonmark 1.6 and will be replaced with "commonmark > unordered_list_markers" in 2.0', \E_USER_DEPRECATED); } else { $deprecatedMarkers = ['*', '+', '-']; } $markers = $this->config->get('commonmark/unordered_list_markers', $deprecatedMarkers); if (!\is_array($markers) || $markers === []) { throw new \RuntimeException('Invalid configuration option "unordered_list_markers": value must be an array of strings'); } return $this->listMarkerRegex = '/^[' . \preg_quote(\implode('', $markers), '/') . ']/'; } } 